import{_ as a,o as t,c as s,ae as e}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"AISHub RPiAIS","description":"","frontmatter":{},"headers":[],"relativePath":"maritime-ais/aishub-rpiais.md","filePath":"maritime-ais/aishub-rpiais.md"}'),n={name:"maritime-ais/aishub-rpiais.md"};function r(o,i,p,l,h,g){return t(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="aishub-rpiais" tabindex="-1">AISHub RPiAIS <a class="header-anchor" href="#aishub-rpiais" aria-label="Permalink to &quot;AISHub RPiAIS&quot;">​</a></h1><p><a href="https://www.aishub.net/ais-dispatcher?tab=linux" target="_blank" rel="noreferrer">https://www.aishub.net/ais-dispatcher?tab=linux</a></p><h2 id="ais-dispatcher-linux" tabindex="-1">AIS Dispatcher - Linux <a class="header-anchor" href="#ais-dispatcher-linux" aria-label="Permalink to &quot;AIS Dispatcher -  Linux&quot;">​</a></h2><p>AIS Dispatcher for Linux supports wide range of Linux distributions on x86_64 / ARM architectures (including Raspberry Pi).</p><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://www.aishub.net/downloads/dispatcher/install_dispatcher</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_dispatcher</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install_dispatcher</span></span></code></pre></div><h3 id="opening-ais-dispatcher-configuration" tabindex="-1">Opening AIS Dispatcher configuration <a class="header-anchor" href="#opening-ais-dispatcher-configuration" aria-label="Permalink to &quot;Opening AIS Dispatcher configuration&quot;">​</a></h3><p>Start your browser and open URL:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">IPADDRESS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (change </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">IPADDRESS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> with</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">IP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> address)</span></span></code></pre></div><p>Default web login credentials are:</p><ul><li>Username: admin</li><li>Password: admin</li></ul><p>WARNING Don&#39;t forget to change the default password after the first login!</p><h3 id="configuring-ais-dispatcher" tabindex="-1">Configuring AIS Dispatcher <a class="header-anchor" href="#configuring-ais-dispatcher" aria-label="Permalink to &quot;Configuring AIS Dispatcher&quot;">​</a></h3><p>After login the web page displays the current status of your AIS station:</p><p><img src="https://www.aishub.net/images/pages/rpiais/config_1.png" alt="rPiAIS Dashboard"></p><p>To configure your AIS Dispatcher select “Configuration” from the left panel.</p><p><img src="https://www.aishub.net/images/pages/rpiais/config_2.png" alt="rPiAIS Configuration"></p><p>There are 3 sections in the configuration panel:</p><ul><li><strong>Input</strong> – configuration of connection to your AIS receiver/data source.</li><li><strong>Output</strong> – configuration of the destinations where AIS data will be forwarded to</li><li><strong>Settings</strong> – additional settings and enable/disable of AIS Dispatcher</li></ul><h4 id="input" tabindex="-1">INPUT <a class="header-anchor" href="#input" aria-label="Permalink to &quot;INPUT&quot;">​</a></h4><p>AIS Dispatcher supports 3 input options:</p><ul><li><p><strong>Serial input</strong> (AIS receivers connected via serial/USB interface)38400,8,N,1 settings are applied to the serial interface by default“View devices” button displays all available serial devices in your Raspberry Pi. You can easily select the device where your AIS receiver is connected by clicking on corresponding “Select” button (preferably use selection “By ID” if you don’t have two devices with same ID)WARNING Mаny Raspberry Pi users, who are using serial connection (or AIS shield), have troubles because by default Linux console is enabled on this serial port. If you are using Raspberry OS you should disable the Linux console, <a href="https://www.raspberrypi.org/documentation/configuration/uart.md" target="_blank" rel="noreferrer">follow the instructions on this link</a></p><figure><img src="https://www.aishub.net/images/pages/rpiais/input_serial_devices.png" alt=""><figcaption></figcaption></figure><figure><img src="https://www.aishub.net/images/pages/rpiais/input_serial.png" alt=""><figcaption></figcaption></figure></li><li><p><strong>TCP Client</strong> (AIS Dispatcher creates TCP connection to your AIS receiver/data source)</p><figure><img src="https://www.aishub.net/images/pages/rpiais/input_tcp_client.png" alt=""><figcaption></figcaption></figure></li><li><p><strong>TCP Server</strong> (your AIS data source creates TCP connection to your RPi)</p><figure><img src="https://www.aishub.net/images/pages/rpiais/input_tcp_server.png" alt=""><figcaption></figcaption></figure></li><li><p><strong>UDP Server</strong> (AIS Dispatcher listens for incoming UDP packets)</p><figure><img src="https://www.aishub.net/images/pages/rpiais/input_udp_server.png" alt=""><figcaption></figcaption></figure></li></ul><h4 id="output" tabindex="-1">OUTPUT <a class="header-anchor" href="#output" aria-label="Permalink to &quot;OUTPUT&quot;">​</a></h4><p>Output section contains all destinations where your data will be forwarded to.<br> Current version supports UDP data streaming to 1 or more destination IP addresses / UDP ports.<br> By default, AIS Dispatcher streams data to AISHub anonymous port and your data is displayed at <a href="https://www.vesselfinder.com/" target="_blank" rel="noreferrer">VesselFinder</a></p><figure><img src="https://www.aishub.net/images/pages/rpiais/output.png" alt=""><figcaption></figcaption></figure><h4 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h4><p><img src="https://www.aishub.net/images/pages/rpiais/settings.png" alt="rPiAIS Settings"></p><ul><li><strong>Inactivity timeout</strong> – Restarts TCP connection if no AIS messages have been received for more than specified time interval (in seconds)</li><li><strong>Reconnect timeout</strong> – Time interval (in seconds) between two sequential connection attempts</li><li><strong>Downsampling time</strong> – Reduces outgoing traffic by transmitting only 1 position report per ship in the specified time frame (in seconds from 0 to 60)</li><li><strong>Log verbosity</strong> – Verbosity of log messages (errors only, errors+connection status, errors + connection status + debug info)</li><li><strong>Duplicates removal</strong> – Reduces outgoing traffic by removal of duplicated AIS messages</li><li><strong>Tag</strong> – Adds NMEA v4.10 tags in the beginning of output NMEA sentences</li><li><strong>Non-VDM</strong> – Dispatches all non-VDM (non-AIS) messages (for example GPS messages)</li><li><strong>Enabled</strong> – Start / Stop AIS Dispatcher</li></ul><p>NOTE! Don’t forget to ENABLE AIS Dispatcher and SAVE your configuration!</p><h3 id="map" tabindex="-1">Map <a class="header-anchor" href="#map" aria-label="Permalink to &quot;Map&quot;">​</a></h3><p>If the input configuration is OK it is time to click on Map menu and start having fun with your AIS coverage.</p><figure><img src="https://www.aishub.net/images/pages/rpiais/map.png" alt=""><figcaption></figcaption></figure>`,32)])])}const d=a(n,[["render",r]]);export{u as __pageData,d as default};
